// --- Query depth and complexity analysis ---

const depthLimit = require('graphql-depth-limit');

function createCostAnalysisPlugin(maxCost) {
  return {
    requestDidStart() {
      return {
        didResolveOperation(requestContext) {
          const cost = estimateQueryCost(requestContext.document);
          if (cost > maxCost) {
            throw new Error(
              `Query cost ${cost} exceeds maximum allowed cost of ${maxCost}. Please simplify your query.`
            );
          }
        },
      };
    },
  };
}

function estimateQueryCost(document, costFactor = 1, depth = 0) {
  let totalCost = 0;

  function visit(node, currentDepth) {
    if (!node) return;

    if (node.kind === 'Field') {
      const fieldCost = Math.pow(2, currentDepth);
      totalCost += fieldCost;
    }

    if (node.selectionSet && node.selectionSet.selections) {
      for (const selection of node.selectionSet.selections) {
        visit(selection, currentDepth + 1);
      }
    }

    if (node.definitions) {
      for (const def of node.definitions) {
        visit(def, currentDepth);
      }
    }
  }

  visit(document, 0);
  return totalCost;
}

// --- Rate limiting per IP ---

const rateLimitMap = new Map();
const RATE_LIMIT_WINDOW_MS = 60 * 1000; // 1 minute
const RATE_LIMIT_MAX_REQUESTS = 100;

function rateLimitPlugin() {
  return {
    async requestDidStart(requestContext) {
      const ip = requestContext.context.ip || 'unknown';
      const now = Date.now();

      if (!rateLimitMap.has(ip)) {
        rateLimitMap.set(ip, { count: 1, windowStart: now });
      } else {
        const entry = rateLimitMap.get(ip);
        if (now - entry.windowStart > RATE_LIMIT_WINDOW_MS) {
          entry.count = 1;
          entry.windowStart = now;
        } else {
          entry.count++;
          if (entry.count > RATE_LIMIT_MAX_REQUESTS) {
            throw new Error('Rate limit exceeded. Please try again later.');
          }
        }
      }
    },
  };
}

// Periodically clean up stale rate limit entries
setInterval(() => {
  const now = Date.now();
  for (const [ip, entry] of rateLimitMap.entries()) {
    if (now - entry.windowStart > RATE_LIMIT_WINDOW_MS * 2) {
      rateLimitMap.delete(ip);
    }
  }
}, RATE_LIMIT_WINDOW_MS);

// --- Input validation helpers ---

function sanitizeString(str, maxLength = 5000) {
  if (typeof str !== 'string') return '';
  return str.trim().slice(0, maxLength);
}

function validatePaginationArgs(first, offset) {
  const MAX_PAGE_SIZE = 100;
  const safeFirst = Math.min(Math.max(parseInt(first, 10) || 10, 1), MAX_PAGE_SIZE);
  const safeOffset = Math.max(parseInt(offset, 10) || 0, 0);
  return { first: safeFirst, offset: safeOffset };
}

